import React, { useState } from 'react';

export default function TagInput({ value, onChange, placeholder = '' }) {
  const [draft, setDraft] = useState('');

  const commit = () => {
    const t = draft.trim();
    if (t && !value.includes(t)) onChange([...value, t]);
    setDraft('');
  };

  const remove = (tag) => onChange(value.filter((t) => t !== tag));

  const onKeyDown = (e) => {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault();
      commit();
    } else if (e.key === 'Backspace' && !draft && value.length) {
      onChange(value.slice(0, -1));
    }
  };

  return (
    <div
      style={{
        display: 'flex',
        flexWrap: 'wrap',
        gap: 6,
        alignItems: 'center',
        border: '1px solid #ccc',
        borderRadius: 8,
        padding: 8,
        maxWidth: 420,
      }}
    >
      {value.map((tag) => (
        <span
          key={tag}
          style={{
            display: 'inline-flex',
            alignItems: 'center',
            gap: 6,
            background: '#eef2ff',
            color: '#3730a3',
            borderRadius: 999,
            padding: '4px 10px',
            fontSize: 14,
          }}
        >
          {tag}
          <button
            onClick={() => remove(tag)}
            aria-label={`Remove ${tag}`}
            style={{ border: 'none', background: 'none', cursor: 'pointer', color: '#3730a3' }}
          >
            ✕
          </button>
        </span>
      ))}
      <input
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onKeyDown={onKeyDown}
        onBlur={commit}
        placeholder={placeholder}
        style={{ flex: 1, minWidth: 120, border: 'none', outline: 'none', fontSize: 14, padding: 4 }}
      />
    </div>
  );
}

