import { Component, Input, Output, EventEmitter } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-tag-input',
  template: `
    <div style="display: flex; flex-wrap: wrap; gap: 6px; align-items: center; border: 1px solid #ccc; border-radius: 8px; padding: 8px; max-width: 420px;">
      <span
        *ngFor="let tag of tags"
        style="display: inline-flex; align-items: center; gap: 6px; background: #eef2ff; color: #3730a3; border-radius: 999px; padding: 4px 10px; font-size: 14px;"
      >
        {{ tag }}
        <button (click)="remove(tag)" [attr.aria-label]="'Remove ' + tag" style="border: none; background: none; cursor: pointer; color: #3730a3;">✕</button>
      </span>
      <input
        [value]="draft"
        (input)="draft = $any($event.target).value"
        (keydown)="onKey($event)"
        (blur)="commit()"
        [placeholder]="placeholder"
        style="flex: 1; min-width: 120px; border: none; outline: none; font-size: 14px; padding: 4px;"
      />
    </div>
  `,
})
export class TagInputComponent {
  @Input() tags: string[] = [];
  @Input() placeholder = '';
  @Output() tagsChange = new EventEmitter<string[]>();
  draft = '';

  commit(): void {
    const t = this.draft.trim();
    if (t && this.tags.indexOf(t) === -1) {
      this.tagsChange.emit([...this.tags, t]);
    }
    this.draft = '';
  }

  remove(tag: string): void {
    this.tagsChange.emit(this.tags.filter((t) => t !== tag));
  }

  onBackspace(): void {
    if (!this.draft && this.tags.length) {
      this.tagsChange.emit(this.tags.slice(0, -1));
    }
  }

  onKey(e: KeyboardEvent): void {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault();
      this.commit();
    } else if (e.key === 'Backspace') {
      this.onBackspace();
    }
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Tag Input Demo</h1>
      <app-tag-input [tags]="tags" (tagsChange)="tags = $event" placeholder="Add a tag…"></app-tag-input>
      <p style="color: #666;">Tags: {{ tags.join(', ') || '(none)' }}</p>
    </div>
  `,
})
export class AppComponent {
  tags: string[] = ['react', 'vue'];
}

@NgModule({
  declarations: [AppComponent, TagInputComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
